import "../styles/Team.css";

export default function Team() {
  const centerMember = {
    name: "Your Name",
    role: "Founder / CEO",
    imgSrc: "/path-to-image/you.jpg",
  };

  const outerMembers = [
    { name: "John", role: "Designer", imgSrc: "/path/john.jpg" },   // 0 (top-left)
    { name: "Jane", role: "Dev", imgSrc: "/path/jane.jpg" },        // 1 (top-center)
    { name: "Emily", role: "Manager", imgSrc: "/path/emily.jpg" },  // 2 (top-right)
    { name: "Tom", role: "Engineer", imgSrc: "/path/tom.jpg" },     // 3 (mid-right)
    { name: "Sara", role: "QA", imgSrc: "/path/sara.jpg" },         // 4 (bottom-right)
    { name: "David", role: "DevOps", imgSrc: "/path/david.jpg" },   // 5 (bottom-center)
    { name: "Mike", role: "UX", imgSrc: "/path/mike.jpg" },         // 6 (bottom-left)
    { name: "Lily", role: "Marketing", imgSrc: "/path/lily.jpg" },  // 7 (mid-left)
  ];

  return (
    <section className="team-section">
      <h3>Meet the Team</h3>
      <div className="grid-container">
        {outerMembers.map((member, index) => (
          <div key={index} className={`grid-item pos-${index}`}>
            <img src={member.imgSrc} alt={member.name} />
            <p>{member.name}</p>
            <span>{member.role}</span>
          </div>
        ))}

        <div className="grid-item center">
          <img src={centerMember.imgSrc} alt={centerMember.name} />
          <h4>{centerMember.name}</h4>
          <p className="role">{centerMember.role}</p>
        </div>
      </div>
    </section>
  );
}
